using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the discriminator from "Discriminator" to "$type".
            // Preserve the EF8 property name so existing 500K documents remain readable
            // and raw SQL queries referencing c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the id format from "EntityName|<key>" to just "<key>".
            // Use IdProperty() to keep the EF8 "Product|<key>" format so existing
            // documents are not orphaned.
            entity.Property(p => p.Id)
                  .ToJsonPropertyName("id")
                  .HasValueGenerator<ProductIdValueGenerator>();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 removed sync query support for Cosmos.
        // No convention change needed, but all call sites must use async APIs.
    }
}

